// Get Discord message content safely
const msg = $json.body?.content || $json.content || "";

// Helper function: extract value between labels (stops before next emoji or end)
function getValue(label) {
  const regex = new RegExp(`${label}:\\s*([^\\n]*)`, "i");
  const match = msg.match(regex);
  if (!match) return "";

  // Clean the value and prevent it from capturing next label accidentally
  const value = match[1]
    .replace(/(🧾|🌐|📄|🗂️|👤|📞|📦|🕒|🧑‍💼|📡).*/g, "") // stop at next emoji
    .trim();

  return value || "";
}

// Extract values safely
const name = getValue("🧾 Name");
const website = getValue("🌐 Website");
const intakeForm = getValue("📄 Intake Form");
let onboardingDoc = getValue("🗂️ Onboarding Doc");
const esAssigned = getValue("👤 ES Assigned");
const contactPerson = getValue("📞 Contact Person");
const servicePackage = getValue("📦 Service Package");
const timezone = getValue("🕒 Timezone");
const leadES = getValue("🧑‍💼 Lead ES");
const channel = getValue("📡 Channel");

// 🧠 Make Onboarding Doc clickable (Google Sheets formula)
if (onboardingDoc && onboardingDoc.includes("http")) {
  onboardingDoc = `=HYPERLINK("${onboardingDoc}", "${name || "Form"}")`;
}

// 🗓 Format CreatedAt date
const createdAtRaw = $json.body?.createdAt || $json.createdAt;
const createdAt = createdAtRaw
  ? new Date(createdAtRaw).toISOString().split("T")[0]
  : "";

// ✅ Return final clean structured data
return [
  {
    json: {
      Name: name,
      Website: website,
      IntakeForm: intakeForm,
      OnboardingDoc: onboardingDoc,
      ES_Assigned: esAssigned,
      ContactPerson: contactPerson,
      ServicePackage: servicePackage,
      Timezone: timezone,
      Lead_ES: leadES,
      Channel: channel,
      MessageURL: $json.body?.messageUrl || $json.messageUrl || "",
      SentBy: $json.body?.author || $json.author || "",
      ChannelName: $json.body?.channelName || $json.channelName || "",
      CreatedAt: createdAt,
    },
  },
];

